```aria
// pass() - return success (preferred for all Aria functions)
func:double = int32(int32:x) {
    pass(x * 2);
};

// fail() - return error (preferred for error paths)
func:safe_div = int32(int32:a, int32:b) {
    if (b == 0i32) {
        fail(-1i32);
    }
    pass(a / b);
};

// return - ONLY valid in extern blocks for C ABI interop
// In extern functions, void becomes NIL at the interface (void-to-NIL bridge)
extern "libc" {
    func:exit = void(int32:code);    // C void return
    func:free = void(void*:ptr);     // C void return
    func:puts = int32(string:s);     // C int return
}

func:failsafe = NIL(int32:err_code) {
    println("Fatal error");
    pass(NIL);
};

func:main = int32() {
    int32:result = double(5) ? 0i32;  // result = 10
    int32:div = safe_div(10, 2) ? 0i32;  // div = 5
    println(`result=&{result}, div=&{div}`);
    pass(0i32);
};
```

Key rules:
- `pass(value)` = success return (builds Result with is_error=false)
- `fail(error)` = error return (builds Result with is_error=true)
- `return` = only for extern/C ABI functions (no Result wrapping)
- Bare `return value;` in an Aria function is a compile error
- There is no `void` in Aria — use `NIL` for no-value, `NULL` for no-address

